<header class="page-head"><div><span class="eyebrow">Promosi</span><h1>Diskon</h1></div></header><div class="split"><section class="panel"><div class="table-wrap" tabindex="0" aria-label="Daftar diskon, geser horizontal bila diperlukan"><table><thead><tr><th>Promo</th><th>Produk</th><th>Nilai</th><th>Periode</th></tr></thead><tbody><?php foreach($items as $x):?><tr><td><?=e($x['name'])?></td><td><?=e($x['product_name'])?></td><td><?=$x['discount_type']==='percentage'?e($x['discount_value']).'%':money($x['discount_value'])?></td><td><?=e($x['starts_at']?:'Sekarang')?> – <?=e($x['ends_at']?:'Seterusnya')?></td></tr><?php endforeach?><?php if(!$items):?><tr><td colspan="4" class="empty-cell">Belum ada diskon aktif.</td></tr><?php endif?></tbody></table></div></section><section class="panel sticky discount-panel"><h2>Diskon baru</h2><?php if($products):?><form method="post" action="<?=url('/admin/discounts')?>" class="stack" onsubmit="return validateDiscount(this)"><?=csrf_field()?><label>Nama promo<input name="name" required></label><label>Produk<select name="product_id" required><?php foreach($products as $p):?><option value="<?=$p['id']?>"><?=e($p['name'])?></option><?php endforeach?></select></label><div class="form-grid discount-form-grid"><label>Jenis<select name="discount_type" id="discount-type" onchange="syncDiscountLimit()"><option value="percentage">Persentase</option><option value="fixed">Nominal rupiah</option></select></label><label>Nilai<input id="discount-value" type="number" min="0" step="1" name="discount_value" required></label><label class="wide">Mulai<input type="datetime-local" name="starts_at"></label><label class="wide">Berakhir<input type="datetime-local" name="ends_at"></label></div><button class="button">Aktifkan diskon</button></form><?php else:?><div class="empty-state"><p>Tambahkan produk sebelum membuat diskon.</p><a class="button" href="<?=url('/admin/products/create')?>">Tambah produk</a></div><?php endif?></section></div><script>function syncDiscountLimit(){const t=document.querySelector('#discount-type'),v=document.querySelector('#discount-value');if(!t||!v)return;t.value==='percentage'?v.max=100:v.removeAttribute('max')}function validateDiscount(f){if(f.starts_at.value&&f.ends_at.value&&f.ends_at.value<=f.starts_at.value){alert('Waktu berakhir harus setelah waktu mulai.');f.ends_at.focus();return false}return true}syncDiscountLimit()</script>
